const sn = $('Webhook').first().json.body.sn;
const joborder_number = $input.first().json.body.joborder_number;
const product_phase = $input.first().json.body.product_phase;
const product_series = $input.first().json.body.product_series;
const product_model = $input.first().json.body.product_model;

// 使用正则替换所有换行符（\n、\r）为空字符串
const cleansn = sn.replace(/\s|\/n/g, '');
const cleanjoborder_number = joborder_number.replace(/\s|\/n/g, '');
const cleanproduct_phase = product_phase.replace(/\s|\/n/g, '');
const cleanproduct_series = product_series.replace(/\s|\/n/g, '');
const cleanproduct_model = product_model.replace(/\s|\/n/g, '');
// 返回清理后的数据
return {
  json: {
    body: {
      sn: cleansn,
      joborder_number:cleanjoborder_number,
      product_phase:cleanproduct_phase,
      product_series:cleanproduct_series,
      product_model:cleanproduct_model

    }
  }
};
